  GRAPH <urn:doid> {
    ?disease oboInOwl:hasDbXref ?omim_xref ;
             oboInOwl:hasDbXref ?orpha_xref ;
             rdfs:label ?label .
    FILTER(STRSTARTS(STR(?omim_xref), "MIM:"))
